args.sparql:
SELECT ?player ?playerLabel WHERE {
  ?player wdt:P31 wd:Q5 .
  ?player wdt:P413 wd:Q237122 .
  ?player p:P54 ?membership .
  ?membership ps:P54 wd:Q329812 ;
              pq:P580 ?start .
  OPTIONAL { ?membership pq:P582 ?end }
  ?player rdfs:label ?playerLabel .
  FILTER (lang(?playerLabel) = "en")
  FILTER (?start <= "2021-12-21"^^xsd:date)
  FILTER (!BOUND(?end) || ?end >= "2021-12-21"^^xsd:date)
}
LIMIT 10

